class Solution {
public:
    int findNthDigit(int n) {
        long long count = 1, digits = 1;
        while (n > digits * count) {
            n -= digits * count;
            count *= 10;
            digits++;
        }
        long long start = pow(10, digits - 1);
        long long num = start + (n - 1) / digits;
        string str = to_string(num);
        return stol(str.substr((n - 1) % digits, 1));
    }
};
